export function exportLayeredSchema(input:{targetName:string;pageName:string;eventName:string;activation:LayerActivation;compiled:CompiledLayeredSchema}):string{const rows=Object.entries(input.compiled.properties).map(([path,property])=>{const definition=[property.type?`type ${property.type}`:undefined,property.presence?`presence ${property.presence}`:undefined,property.allowedValues?`allowed ${JSON.stringify(property.allowedValues)}`:undefined,property.expectedValue!==undefined?`equals ${String(property.expectedValue)}`:undefined,property.condition?`condition ${JSON.stringify(property.condition)}`:undefined,property.rules?.length?`rules ${JSON.stringify(property.rules)}`:undefined,property.documentation?`documentation ${property.documentation}`:undefined,property.examples?`examples ${JSON.stringify(property.examples)}`:undefined,property.overrideReferences?.length?`explicit resolution ${property.overrideReferences.join(", ")}`:undefined].filter(Boolean).join(" · "),origins=property.origins.map(({scope,contributorName})=>`${scope} ${contributorName}`).join(" → ");return`${path}: ${definition||"constraint"} · provenance ${origins}`;});return[`${input.targetName} · ${input.pageName} · ${input.eventName}`,...rows,input.activation==="documentation-only"?"Documentation only — not automatically validated":`Activation: ${input.activation}`].join("\n");}
